%[text] $W\_q =\\frac{P\_0 (\\frac{\\lambda \\;}{\\mu \\;\\;})^s \\rho }{s!\\lambda (1-\\rho )^2 }=\\frac{\\left(0\\ldotp 2\\right)(\\frac{40\\;}{30\\;})^2 \\left(\\frac{2}{3}\\right)}{2!40(1-\\left(\\frac{2}{3}\\right){\\left.\\right)}^2 }\\;\\;\\;\\;\\;\\;\\;\\;\\;\\;\\approx \\;\\frac{\\;0\\ldotp 237\\;}{8\\ldotp 89}\\approx 0\\ldotp 0266\\;\\;${"editStyle":"visual"} hours
