%%
%[text] 4\. Set up and run the simulation for this scenario for an 8 hour shift. Generate histograms of  the following:
%[text]  a. the probability of finding 𝑛 customers in the system; overlay with your theoretical results 
%[text] b. the total time customers spend in the system 
%[text] 
%[text] Calculating P\_0, P\_1, P\_2
%NumSamples = 10;
NumSamples = 100;
% Since this is an 8 hour shift, 8(60) = 480 min
%I am running my code in hours so I leave this as 8.
MaxTime = 8;
LogInterval = 1/60;
%P0 = (1 - (lambda/(2*mu)) )/(1 + (lambda)*(2*mu));
P0 = 1./(    1 +(lambda/mu) + ((lambda/mu)^2)/ (2*(1-(lambda/(2*mu))))  );
%Pn= 2*(lambda/(2*mu))^n*(P0);
P1= 2*(lambda/(2*mu))*(P0);
P2= 2*(lambda/(2*mu))*(lambda/(2*mu))*(P0);
nMax = 5;
P = zeros([1, nMax+1]);
%P(1) = P1;
P(1) = P0;
fprintf("These are the theoretical calculations:"); %[output:85d2677e]
fprintf("P(0) = %f\n", P0); %[output:6ee18732]
for n = 1:nMax %[output:group:6aadf1fe]
    P(n+1) = 2*(lambda/(2*mu))^n*(     P0 );
    fprintf("P(" + n +") = %f\n", P(n+1)); %[output:9d9e01ca]
   
end %[output:group:6aadf1fe]






rng("default");
QSamples = cell([NumSamples, 1]);




for SampleNum = 1:NumSamples %[output:group:49de05b1]
    fprintf("Working on sample %d\n", SampleNum); %[output:34ddb47e]
    q = ServiceQueue( ...
        ArrivalRate=lambda, ...
        DepartureRate=mu, ...
        NumServers=s, ...
        LogInterval=LogInterval);
    q.schedule_event(Arrival(random(q.InterArrivalDist), Customer(1)));
    run_until(q, MaxTime);
    QSamples{SampleNum} = q;
end %[output:group:49de05b1]




NumInSystemSamples = cell([NumSamples, 1]);
for SampleNum = 1:NumSamples
    q = QSamples{SampleNum};
    % Pull out samples of the number of customers in the queue system. Each
    % sample run of the queue results in a column of samples of customer
    % counts, because tables like q.Log allow easy extraction of whole
    % columns like this.
    NumInSystemSamples{SampleNum} = q.Log.NumWaiting + q.Log.NumInService;
end

NumInSystemSamples = cellfun( ...
    @(q) q.Log.NumWaiting + q.Log.NumInService, ...
    QSamples, ...
    UniformOutput=false);


%%
%[text] Calculating mu\_0 , mu\_1, mu\_2
%%
%{
if NumInSystem == 0
    RateDeparture = 0;
elseif NumInSystem == 1
    RateDeparture = mu;
else
    RateDeparture = 2 * mu; 
    end
    %}

%%
%[text] L\_q  Calculation
%%

WaitingInSystemSamples = cell([NumSamples, 1]);
for SampleNum = 1:NumSamples
    q = QSamples{SampleNum};
    % Pull out samples of the number of customers in the queue system. Each
    % sample run of the queue results in a column of samples of customer
    % counts, because tables like q.Log allow easy extraction of whole
    % columns like this.
    WaitingInSystemSamples{SampleNum} = q.Log.NumWaiting ;
end
%WaitingInSystemSamples = cellfun( ...
    %@(q) q.Log.NumWaiting , ...
    %QSamples, ...
   % UniformOutput=false);
%ExpectedWaitingInSystem = vertcat(WaitingInSystemSamples{:});
% Corrected Option Two
WaitingInSystemSamples = cellfun(@(q) q.Log.NumWaiting, ...
    QSamples, UniformOutput= false);
% To get L_q (Expected number of customers waiting)
NumWaiting = vertcat(WaitingInSystemSamples{:});
meanNumWaiting = mean(NumWaiting);
fprintf("Mean number waiting (L_q): %f\n", meanNumWaiting); %[output:492cc97f]

NumInSystem = vertcat(NumInSystemSamples{:});


%%
%[text] W\_q  and L  Calculation 
%%



WaitingTimeInSystemSamples = cell([NumSamples, 1]);
for SampleNum = 1:NumSamples
    q = QSamples{SampleNum};
    % The next command has many parts.
    %
    % q.Served is a row vector of all customers served in this particular
    % sample.
    % The ' on q.Served' transposes it to a column.
    %
    % The @(c) ... expression below says given a customer c, compute its
    % departure time minus its arrival time, which is how long c spent in
    % the system.
    %
    % cellfun(@(c) ..., q.Served') means to compute the time each customer
    % in q.Served spent in the system, and build a column vector of the
    % results.
    %
    % The column vector is stored in TimeInSystemSamples{SampleNum}.
    WaitingTimeInSystemSamples{SampleNum} = ...
        cellfun(@(c) c.BeginServiceTime - c.ArrivalTime , q.Served');
end
WaitingTimeInSystemSamples = cellfun( ...
    @(q) cellfun(@(c) c.BeginServiceTime - c.ArrivalTime , q.Served'), ...
    QSamples, ...
    UniformOutput=false);
ExpectedWaitingTime = vertcat(WaitingTimeInSystemSamples{:});
meanWaitTime = mean(ExpectedWaitingTime);
fprintf("Mean waiting time (W_q): %f\n", meanWaitTime); %[output:249bf14f]


meanNumInSystem = mean(NumInSystem);
fprintf("Mean number in system (L) : %f\n", meanNumInSystem); %[output:3915a421]


