h = histogram(ax, NumInSystem, Normalization="probability", BinMethod="integers"); %[output:18ae10cb]

plot(ax, 0:nMax, P, 'o', MarkerEdgeColor='k', MarkerFaceColor='r'); %[output:18ae10cb]

title(ax, "Number of Customers in the System"); %[output:18ae10cb]
xlabel(ax, "Count (n)"); %[output:18ae10cb]
